-- [ ObfusPro+ ]
local NwgRH = bit32 or bit or error("ObfusPro+: Environment error");
local function rjDwve(XyCsf)
    local kzCYfIFg = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local gjjWX = string.gsub(XyCsf, '[^' .. kzCYfIFg .. ']', '')
    local fOMdVVH = {}
    for wQtg = 1, #gjjWX, 4 do
        local fke, KBN, Ksg, sKg = string.byte(gjjWX, wQtg, wQtg + 3)
        if not fke then break end
        local UnXj = string.find(kzCYfIFg, string.char(fke)) - 1
        local qozt = string.find(kzCYfIFg, string.char(KBN)) - 1
        local bkdI = Ksg and string.find(kzCYfIFg, string.char(Ksg)) - 1 or 0
        local enOI = sKg and string.find(kzCYfIFg, string.char(sKg)) - 1 or 0
        local ePLR = UnXj * 262144 + qozt * 4096 + bkdI * 64 + enOI
        local SvfY = NwgRH.band(NwgRH.rshift(ePLR, 16), 255)
        table.insert(fOMdVVH, string.char(NwgRH.bxor(SvfY, 141)))
        if Ksg and string.char(Ksg) ~= '=' then
            SvfY = NwgRH.band(NwgRH.rshift(ePLR, 8), 255)
            table.insert(fOMdVVH, string.char(NwgRH.bxor(SvfY, 141)))
        end
        if sKg and string.char(sKg) ~= '=' then
            SvfY = NwgRH.band(ePLR, 255)
            table.insert(fOMdVVH, string.char(NwgRH.bxor(SvfY, 141)))
        end
    end
    return table.concat(fOMdVVH)
end
local CiGutE = math.sin(270);
local MmcjmfnU = [===[]===]
local mSemoNc = rjDwve(MmcjmfnU)
local ncgcVt = math.sin(435);
task.spawn(assert(loadstring(mSemoNc)))
